mapper.select:
SELECT e.id, e.category_id AS categoryId, c.category_name AS categoryName, e.title, e.cover_url AS coverUrl, e.location, e.start_time AS startTime, e.end_time AS endTime, e.signup_deadline AS signupDeadline, e.max_participants AS maxParticipants, e.need_audit AS needAudit, e.status AS baseStatus, AS runtimeStatus, e.signup_count AS signupCount, e.approved_count AS approvedCount, e.checkin_count AS checkinCount, (e.max_participants - e.signup_count) AS remainingSlots FROM event_info e LEFT JOIN event_category c ON c.id = e.category_id
e.status = 'published'
AND e.title LIKE CONCAT('%', #{query.title}, '%')
AND e.category_id = #{query.categoryId}
AND = #{query.runtimeStatus}
ORDER BY e.start_time DESC, e.id DESC

SELECT e.id, e.category_id AS categoryId, c.category_name AS categoryName, e.title, e.cover_url AS coverUrl, e.location, e.start_time AS startTime, e.end_time AS endTime, e.signup_deadline AS signupDeadline, e.max_participants AS maxParticipants, e.need_audit AS needAudit, e.status AS baseStatus, AS runtimeStatus, e.signup_count AS signupCount, e.approved_count AS approvedCount, e.checkin_count AS checkinCount, (e.max_participants - e.signup_count) AS remainingSlots FROM event_info e LEFT JOIN event_category c ON c.id = e.category_id
AND e.title LIKE CONCAT('%', #{query.title}, '%')
AND e.category_id = #{query.categoryId}
AND e.status = #{query.baseStatus}
AND = #{query.runtimeStatus}
ORDER BY e.create_time DESC, e.id DESC
